INSERT INTO `comments` VALUES (1,3,'123','2025-10-27 16:41:45','2025-10-27 16:41:45'),(2,3,'1234','2025-10-27 18:54:02','2025-10-27 19:28:21'),(6,3,'ffff','2025-11-06 10:35:10','2025-11-06 10:35:10'),(7,3,'@sailo fdddgggg','2025-11-06 10:35:15','2025-11-06 10:35:19'),(8,3,'jjjjj','2025-11-10 10:19:59','2025-11-10 10:19:59'),(9,3,'@sailo jjjj','2025-11-10 10:20:07','2025-11-10 10:20:07'),(10,10,'寫得真美！特別喜歡你形容翠玉白菜那一段，溫潤的詞句讓古老的文物多了生命。希望之後能看到你分享更多關於故宮的小細節或冷知識！','2025-11-11 11:03:19','2025-11-11 11:03:19'),(11,11,'好漂亮!','2025-11-11 11:04:22','2025-11-11 11:04:22'),(12,11,'@睿智的蛤蜊 寫的真好','2025-11-11 11:04:36','2025-11-11 11:04:36'),(13,12,'我也有去過故宮','2025-11-11 11:05:36','2025-11-11 11:05:36'),(14,13,'故宮好玩','2025-11-11 11:06:12','2025-11-11 11:06:12'),(15,14,'@Loiza 確實','2025-11-11 11:07:16','2025-11-11 11:07:16'),(16,3,'@睿智的蛤蜊 謝謝你的留言！? 我也特別喜歡翠玉白菜那一段，每次看到都覺得它不只是藝術品，更像是時間的縮影。之後一定會再分享一些故宮裡有趣的文物故事，還有那些容易被忽略的小角落，敬請期待！','2025-11-11 11:07:59','2025-11-11 11:07:59');
/*!40000 ALTER TABLE `comments` ENABLE KEYS */;
