DROP TABLE IF EXISTS `customer_service_ratings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `customer_service_ratings` (
  `id` int NOT NULL AUTO_INCREMENT,
  `room_id` int NOT NULL COMMENT '聊天室ID',
  `user_id` int NOT NULL COMMENT '評分者ID（客戶）',
  `agent_id` int NOT NULL COMMENT '被評分者ID（客服人員）',
  `rating` int NOT NULL COMMENT '評分（1-5星）',
  `comment` text COLLATE utf8mb4_unicode_ci COMMENT '評價留言（選填）',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '評分時間',
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_room_rating` (`room_id`),
  KEY `idx_room_id` (`room_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_agent_id` (`agent_id`),
  KEY `idx_rating` (`rating`),
  KEY `idx_created_at` (`created_at`),
  CONSTRAINT `fk_rating_agent` FOREIGN KEY (`agent_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_rating_room` FOREIGN KEY (`room_id`) REFERENCES `customer_service_rooms` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_rating_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `chk_rating_value` CHECK (((`rating` >= 1) and (`rating` <= 5)))
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='客服滿意度評分表 - 記錄使用者對客服的評價';
/*!40101 SET character_set_client = @saved_cs_client */;

