/*!40000 ALTER TABLE `posts` DISABLE KEYS */;
INSERT INTO `posts` VALUES (13,10,'奇美博物館美術展隨拍～莫內畫作欣賞','今天到奇美博物館逛美術展，展出了好幾幅莫內的經典畫作，真的很震撼！展場空間寬敞明亮，走在畫作之間能慢慢欣賞細節，每一筆顏色、光影都讓人想停下來仔細看。除了莫內，還有其他歐美畫家的作品，整個展覽感覺很完整又豐富。拍照時注意不要打擾其他觀眾，光線拍起來剛好能呈現畫作的柔和色調。逛完感覺眼睛和心情都被洗滌了一遍，下次想靜靜欣賞畫作的話，奇美博物館真的很適合✨','travel',13,NULL,1,8,'2025-11-10 20:48:17','2025-11-10 21:05:38'),(17,10,'台北兩天一夜小旅行～101＋故宮＋士林夜市','這次安排了兩天一夜的台北小旅行，行程滿滿但很充實✨ 第一天先去台北101拍照，從觀景台俯瞰整個城市，風景真的超美。接著跑到故宮博物院，看了好多歷史文物，每個展品都很有故事感，慢慢逛超適合喜歡文化的小旅行。晚上則到士林夜市大吃特吃，香酥雞排、珍珠奶茶、小籠包都必吃～第二天早上再隨意逛了幾個小景點就結束，雖然行程緊湊，但每一站都很值得拍照留念，感覺兩天就把台北的小確幸都收集完了','travel',14,NULL,1,1,'2025-11-10 21:09:41','2025-11-10 21:09:43'),(18,10,'中央公園聖誕樹小散步','今天跟朋友吃飯順便去中央公園看看聖誕樹～樹真的很大，燈飾亮起來整個晚上氣氛超有節日感✨ 拍了幾張照片留作紀念，還順便在附近散步聊天，吃飽飯的小確幸就是這樣。雖然人有點多，但大家都笑著拍照，感覺很熱鬧又溫暖。天氣涼涼的，燈光和街景搭配起來，散步的感覺特別舒服，下次可以帶熱可可來慢慢逛～','life',NULL,39,1,3,'2025-11-10 21:11:35','2025-11-10 21:28:43'),(19,10,'朋友生日一起手作蛋糕','今天是朋友生日，我們一起去 DIY 教室手作蛋糕～自己動手做真的很有趣！從揉麵糰、裝飾到最後撒上巧克力粉，每個步驟都超療癒。大家邊做邊聊天，氣氛很輕鬆，還互相比較誰的蛋糕比較可愛XD 做完後拍了幾張照片留作紀念，最後把蛋糕帶回去給壽星切，朋友超開心～這種小活動真的很適合和朋友一起度過特別的日子✨','life',NULL,NULL,1,1,'2025-11-10 21:12:09','2025-11-10 21:12:10'),(20,10,'士林夜市小吃','今天晚上跑去士林夜市大吃一番，整個人好開心?！香酥雞排一定要吃，外酥內嫩，咬一口就超滿足。還試了大腸包小腸和珍珠奶茶，真的是經典必吃啊✨！夜市人雖多，但邊走邊吃慢慢逛，感覺像小冒險，每個攤位都想試一點。拍了幾張小吃照?，燈光和熱鬧的氛圍拍出來超有夜市感。建議大家肚子空一點來，不然真的吃不完～週末晚上就這樣吃美食逛夜市最開心啦(｡>ω<｡)♡','food',NULL,5,1,2,'2025-11-10 21:14:23','2025-11-10 21:14:52'),(21,11,'台南安平古堡 + 赤崁樓','今天跑去台南小旅行，第一站安平古堡?，古色古香又好拍照?。再到赤崁樓感受歷史氣息，每個角落都能拍到文藝感照片～天氣涼涼的，走在古蹟裡慢慢逛很舒服。兩個景點距離不遠，安排一天就能輕鬆完成。途中還順便吃了安平老街小吃，超飽足！歷史、文化、美食一次收集完，整個旅程很充實，也很適合拍照留念✨','travel',15,NULL,1,2,'2025-11-10 21:20:26','2025-11-10 21:20:34'),(22,11,'台中歌劇院','今天跑去台中歌劇院拍照，建築真的超有特色✨！裡面曲線設計超美，隨便一個角度都很好拍?。光線透進大廳時，影子和光影交錯，整個空間瞬間變成電影場景～邊走邊欣賞建築細節，每個樓梯、每個拱門都想拍下來。這裡不只是拍照景點，也很適合慢慢散步，享受建築藝術帶來的美感。喜歡攝影的朋友真的不能錯過，拍完照片整個人都覺得充滿靈感?','travel',NULL,13,1,1,'2025-11-10 21:22:18','2025-11-10 21:22:19'),(23,11,'吉卜力公園無臉男拍照','今天終於跑去吉卜力公園，一大早就去排隊，只為了跟無臉男拍張合照。排隊時間比想像中久，大家都耐心等待，也有不少人邊聊天邊打發時間。站在無臉男前面拍照的瞬間整個人超開心，覺得一切等待都值得了。園區裡的裝置和景觀也很有趣，隨手拍幾張照片都很有動畫感。雖然排隊花了不少時間，但體驗過程很有趣，還順便逛了附近的小店和咖啡區。覺得這種熱門景點雖然人多，但能親眼看到喜歡的角色，拍照留念真的很開心，也算是一次難忘的小旅行。','travel',NULL,NULL,1,3,'2025-11-10 21:24:19','2025-11-10 21:27:30'),(24,11,'DIY 手作蠟燭','今天去參加了一堂 DIY 蠟燭體驗課，整個過程超有趣～老師先介紹了各種顏色和香味，還有簡單的造型技巧，我選了薰衣草香和粉紫色調。從融蠟到倒入模具，每一步都很療癒，邊做邊跟同學聊天，感覺時間一下就過了。最有趣的是自己裝飾小配件，像是乾花或亮片，最後做出來的蠟燭完全是自己的風格。帶回家後還特別拍了幾張照片，放在桌上超有氛圍～覺得這種手作活動很適合週末，既能放鬆，又能做出實用又好看的小物，還能當作禮物送給朋友，整個過程真的很滿足✨','life',NULL,NULL,1,2,'2025-11-10 21:24:57','2025-11-10 21:27:50'),(25,11,'夢時代樓上電影院拍照隨手記','今天跑去夢時代樓上的電影院看看場景，真的超適合拍照！光線和空間設計都很棒，不管是樓梯、走廊還是座位區都很好取景。隨手一拍就能拍出有氛圍的照片，整個空間帶點電影感，拍起來很有質感。建議可以利用自然光或者樓上小燈光，拍出層次感會更好。喜歡拍攝的朋友，這裡絕對值得來捕捉幾張照片～✨','photo',NULL,67,1,1,'2025-11-10 21:26:49','2025-11-10 21:26:50'),(26,12,'駁二微型展的午後小確幸','今天在駁二藝術特區逛到一場微型展，小小的空間裡卻藏著滿滿創意。每件作品都充滿巧思，從色彩搭配到細節設計，都讓人忍不住停下腳步細細觀賞。展場雖迷你，但每個角落都有故事，拍下照片時，光線和陰影交錯，彷彿把藝術也定格在了鏡頭裡。走在展覽中，感覺像是和藝術家進行了一場靜默的對話，每個微小細節都能帶來意外的驚喜。微型展的魅力，或許就在於它讓人能慢慢沉浸，而不被人潮打擾。','travel',16,NULL,1,1,'2025-11-10 21:33:46','2025-11-10 21:33:48'),(27,12,'澄清湖棒球賽','今天特地跑去澄清湖看棒球比賽，現場氣氛真的超熱鬧！球場人潮滿滿，大家一起為喜歡的隊伍加油吶喊，整個人都被感染到超興奮。找了靠近外野的位置坐下，可以清楚看到投手和打擊手的動作，感覺每一球都好緊張。中場還有小吃區，熱狗、炸物和啤酒，邊吃邊看比賽很過癮。球場周圍還有湖景，風景不錯，拍照起來也很有運動感。雖然一整場比賽大約三個小時，但完全不覺得無聊，感覺短暫逃離日常，又充滿現場活力。棒球場的熱血氣氛真的值得體驗一次！','travel',NULL,NULL,1,1,'2025-11-10 21:35:33','2025-11-10 21:35:34'),(28,12,'東京迪士尼萬聖節小旅行','這次去東京迪士尼剛好碰上萬聖節，整個園區都超有氣氛? 入口的裝飾、街道上的南瓜擺設、還有遊行表演，拍照每一個角落都好看。最喜歡的是穿著萬聖節主題服裝的米奇和朋友們，超可愛～雖然人很多，但排隊玩遊樂設施也不會太累，重點是氣氛很熱鬧，每個細節都充滿節日感。建議可以早點進園，慢慢逛慢慢拍照，整個萬聖節體驗會更完整～✨','travel',NULL,NULL,1,3,'2025-11-10 21:38:31','2025-11-10 22:12:59'),(29,12,'週末手作盆栽','週末去手作課程做了小盆栽?，挑選了迷你多肉和小花盆，自己搭配土壤、擺放位置，整個過程超放鬆。老師還教了簡單的澆水和養護技巧，我邊做邊拍照?，每個角落都好可愛～最後完成的小盆栽擺在桌上，整個房間都像有了小森林✨。覺得這種小活動很療癒，也很適合給朋友做生日小禮物，自己動手真的比買現成的還有成就感(｡>﹏<｡)♡','life',NULL,NULL,1,1,'2025-11-10 21:40:43','2025-11-10 21:40:44'),(30,12,'海邊落日小旅行','今天傍晚去了附近的海邊散步，看著太陽慢慢落下，天空和海面染成橘紅色，景色真的很美。沿著沙灘走，踩著細軟的沙子，聽著海浪拍打聲，整個人都放鬆下來。沿途還看到幾個人在拍攝落日和海景，隨手拍了幾張照片留作紀念。風不大，但帶著海的味道，邊散步邊呼吸覺得特別舒服。最後坐在岸邊看太陽完全落下，天色漸暗，海面閃著微光，感覺整個下午都被洗滌了一遍。這種小旅行簡單卻療癒，非常適合週末短暫放空。','travel',NULL,NULL,1,1,'2025-11-10 21:42:21','2025-11-10 21:42:29'),(31,12,'手作香皂體驗','今天參加了一堂手作香皂課，從選香味、顏色到模具，都自己動手完成。老師還教了簡單的切割和壓模技巧，過程很療癒，也可以慢慢發揮創意。完成的香皂帶著淡淡花香，放在房間裡增添氛圍，也能當作小禮物送朋友。邊做邊拍照，記錄每個步驟，完成品出來的樣子比想像中還可愛。覺得這種小手作活動不僅放鬆心情，還能增添生活趣味，週末抽個幾個小時就能有滿滿成就感。','life',NULL,NULL,1,1,'2025-11-10 21:46:33','2025-11-10 21:46:34'),(32,12,'限量布丁狗娃娃加購活動','今天去超市剛好遇到布丁狗限量娃娃的加購活動，只要買湯圓就可以加購，心裡立刻覺得很划算。湯圓買好了之後排隊加購，現場娃娃真的很迷你又可愛，毛茸茸的質感超討喜。拿到手的瞬間就忍不住拍了幾張照片留念，擺在桌上整個人心情都變好。覺得這種小活動超有趣，不只是買到實用的食物，還能順便收集可愛的周邊。下次如果有類似限量活動，一定還想再去碰碰運氣，順便買點小零食回家，整個過程既有趣又滿足。','life',NULL,NULL,1,1,'2025-11-10 21:48:24','2025-11-10 21:49:12'),(33,12,'東區小火鍋','今天跑去東區新開的小火鍋店試試，OMG～真的太好吃啦?✨！我點了海鮮鍋，裡面蝦子超大隻，蛤蠣超新鮮，湯頭又香又濃，喝一口就暖到心裡去了。店裡環境也很舒服，座位不擁擠，拍照超上鏡?。最喜歡的是自己涮菜的過程，每片肉每片菜都能慢慢享受。服務也很貼心，還附小菜和味噌湯，整個套餐很完整～跟朋友一起吃邊聊天，超級療癒的下午/晚餐時光(｡･ω･｡)♡。如果你也想找地方放鬆又吃得飽，這家小火鍋絕對值得一試～\'','food',NULL,NULL,1,1,'2025-11-10 21:52:33','2025-11-10 21:52:35'),(34,13,'北投溫泉小旅行','週末跑去北投泡湯啦～? 一到溫泉區就覺得整個人放鬆了，微微的霧氣和山景搭配起來超療癒。選了露天溫泉，坐在熱騰騰的水裡，看著遠方綠意盎然，真的有種逃離城市的感覺?。旁邊還有小販賣溫泉蛋和茶點，邊泡邊吃小零食，好愜意～順便拍了幾張照片，光影和霧氣的效果超有氛圍?。整個小旅行不趕路，慢慢走慢慢拍照，感覺一天就充滿了放鬆的幸福感。推薦給想放鬆又想拍照的小夥伴，北投真的很適合短程小旅行～✨','travel',17,NULL,1,1,'2025-11-10 21:56:27','2025-11-10 21:57:07'),(35,13,'台中＋台南一日遊行程分享','這次安排了台中台南的小旅行，一天跑了好幾個景點～先到台中歌劇院看看建築，裡面空間設計超有特色，拍照超好看✨ 接著到逢甲夜市吃小吃，雞排、章魚燒都超讚，邊走邊吃超過癮。之後開車下南部，先去安平古堡感受歷史氛圍，再到赤崁樓拍照留念，每個景點都很有特色又好拍照。雖然一天跑很多地方有點累，但風景、美食和歷史都收穫滿滿，下次想分開慢慢逛也可以～','travel',18,NULL,1,1,'2025-11-10 22:00:12','2025-11-10 22:00:13'),(36,13,'山城咖啡小旅行','今天去了附近的小山城咖啡村☕️，整個地方像世外桃源，咖啡香氣混著樹木味道，超舒服。找了個靠窗的位置坐下，遠方山景搭配微霧，隨手拍都像明信片?。咖啡店還有手工甜點，巧克力塔和檸檬派都超好吃～邊吃邊看山景，完全放鬆。走出咖啡店後沿著小徑散步，遇到小河和石橋，整個小旅行感覺很悠閒。這種隨興走走的小景點真的很適合週末，拍照又療癒✨','travel',NULL,NULL,1,1,'2025-11-10 22:03:48','2025-11-10 22:03:51'),(37,13,'Chiikawa 快閃店探訪','今天跑去逛 Chiikawa 快閃店，整個店面超可愛，牆上、架上都是各種小動物周邊，讓人瞬間少女心大爆發。挑了幾個迷你吊飾和貼紙拍照留念，擺在桌上超可愛。店裡還有拍照區，可以和大型公仔合照，背景布置也很用心，隨手拍照就很上鏡。現場人氣很旺，但排隊動線很順，逛起來不會太擁擠。覺得這種快閃店很適合短暫放鬆，順便收集小物當紀念，也很適合帶朋友一起來拍照打卡。今天收穫滿滿，心情也跟著可愛起來。','life',NULL,NULL,1,1,'2025-11-10 22:05:18','2025-11-10 22:05:19'),(38,13,'隱藏版咖啡館甜點','今天發現一家隱藏在巷弄裡的咖啡館，主打手工甜點和特色咖啡。店面小巧溫馨，裝潢簡單卻很有氛圍，坐下來就覺得放鬆。點了店內人氣的焦糖布丁和黑糖拿鐵，布丁口感綿密滑順，甜度剛好；黑糖拿鐵香氣濃郁，喝起來暖暖的。邊吃邊看店裡的裝飾細節，拍了幾張照片留念，整個下午過得很愜意。這種小店雖然隱藏，但真的很適合想找安靜空間享受甜點的人，下次朋友來也想帶他們來試試。','food',NULL,NULL,1,1,'2025-11-10 22:07:07','2025-11-10 22:07:09'),(39,13,'淡水老街','今天趁天氣好去了淡水老街走走，整個河邊風景超美?！沿著河邊散步，買了阿給、魚酥和花生冰淇淋邊走邊吃，超級滿足～街上的小店也很可愛，每個角落都很好拍照?。特別喜歡夕陽慢慢落下時，河面閃閃發亮，配上老街小吃，感覺很有味道。雖然人多，但走慢一點就可以慢慢欣賞風景。隨手拍了好幾張照片，整個旅程感覺輕鬆又愜意。淡水老街真的很適合週末小旅行～','travel',NULL,NULL,1,1,'2025-11-10 22:10:05','2025-11-10 22:10:07'),(40,13,'哈利波特影城的迷你霍格華茲','今天去了哈利波特影城，看到等比例的霍格華茲模型，真的超震撼！從樓梯到塔樓每個細節都做得很精緻，光影打在城堡上拍照效果超棒? 隨手一拍就像真的走進電影場景。建議可以從不同角度拍，特別是斜側面或有前景的構圖，會讓城堡看起來更有立體感。喜歡攝影或哈利波特的朋友，這裡絕對值得好好捕捉幾張照片～✨','photo',NULL,NULL,1,1,'2025-11-10 22:12:12','2025-11-10 22:12:24'),(41,14,'山城茶園走走','今天去了附近的山城茶園散步，茶樹整齊排列，空氣裡都是清新的茶香，整個人感覺放鬆。沿著小路慢慢走，還看到農人採茶的景象，順便拍了幾張照片紀念。茶園裡有小平台可以休息，邊喝茶邊欣賞山景，風景很舒服。這種短程旅行很適合週末，不用太遠就能享受自然景色，又能拍到好看的照片，感覺特別悠閒。走完一圈回程，心情整個人都平靜下來，像是給自己充了一整天的電。','travel',NULL,NULL,1,1,'2025-11-10 22:15:39','2025-11-10 22:15:45'),(42,14,'小鎮古街散步','今天去了一個附近的小鎮古街散步，街道兩旁是老房子和小店，氣氛很安靜又有味道。沿街逛了幾間特色小店，買了手工小物和糕點，邊走邊拍照，很有旅遊感。街上偶爾有當地居民走過，讓整個小鎮感覺很生活化而不是觀光味太重。天氣晴朗，光線很好，隨手拍的照片都很自然。整個下午慢慢走慢慢逛，感覺像短暫逃離城市，心情很放鬆，也收穫了幾張美照作紀念。','travel',NULL,NULL,1,1,'2025-11-10 22:16:49','2025-11-10 22:16:59'),(43,14,'下午花藝課','今天參加了下午的花藝課，做了一個小型桌花。老師先介紹各種花材和搭配技巧，自己挑選了喜歡的花色，慢慢插成花束。過程很療癒，也能專注在細節上，每個角度都想拍照紀念。完成後的花束放在桌上，整個空間都變得溫馨起來。覺得這種小手作活動非常適合放鬆心情，也能提升生活品味，週末抽個幾小時就能收穫成就感，還能增添家裡的美感。','life',NULL,NULL,1,1,'2025-11-10 22:18:09','2025-11-10 22:18:15'),(44,14,'隱藏咖哩小店','今天去了一家巷子裡的咖哩小店，招牌是雞肉咖哩，香氣十足，一上桌就聞到濃郁香料味。咖哩醬濃而不膩，雞肉軟嫩多汁，配上香噴噴的白飯剛剛好。店裡空間雖然小，但乾淨整齊，裝潢帶點日式風格，拍照也很有感覺。點餐時還順便加了店家特製的泡菜和小菜，味道意外地搭。吃完整個人覺得很滿足，也覺得這種巷弄小店特別有驚喜，適合喜歡發現隱藏美食的人。下次想帶朋友一起來嘗試其他口味。','food',NULL,NULL,1,1,'2025-11-10 22:19:08','2025-11-10 22:19:14'),(45,14,'隱藏義大利麵小館','今天試了巷弄裡的義大利麵小館，點了經典奶油蘑菇義大利麵，味道濃郁卻不膩，麵條軟硬適中，非常入味。店裡空間不大，但簡單溫馨，氣氛很舒適。服務人員也很親切，餐點上桌速度快，搭配小沙拉和濃湯，整個套餐吃完很滿足。隨手拍了幾張餐點照片，擺盤簡單卻有質感。覺得這種隱藏在小巷的小店特別有驚喜，適合想找安靜又好吃餐點的人，下次還想來試試其他口味。','food',NULL,NULL,1,1,'2025-11-10 22:20:08','2025-11-10 22:20:09'),(46,10,'刮刮樂中一萬小確幸','今天去便利商店順手買了一張刮刮樂，結果竟然刮中一萬塊，整個人超級驚喜！站在收銀台的時候手還微微發抖，完全沒想到會中這麼多。旁邊的店員和我一起歡呼，氣氛超有趣。拿到現金後心情整個大好，順便買了幾樣小零食犒賞自己。覺得這種意外小確幸特別療癒，就算只是短短幾分鐘，也能讓整天心情變亮。回家還拍了刮刮樂照片留念，想說以後再也不要低估運氣，偶爾嘗試一下真的會有驚喜。','life',NULL,NULL,1,4,'2025-11-10 22:22:51','2025-11-11 10:55:50'),(47,3,'故宮一日遊','走進故宮，彷彿踏入一段靜止的時光。晨光灑在翠綠的琉璃瓦上，金黃色的屋脊閃閃發光，像是歷史在輕聲呼吸。遊人步入大殿之間，低語交錯，卻不敢太大聲，生怕驚擾了沉睡的朝代。展廳裡的玉器與青銅器靜靜陳列，每一件都承載著數百年的故事。當我凝視那件溫潤的翠玉白菜，竟覺得時間在這裡變得柔軟，讓人忍不住多看一眼。走出展館，微風拂過松林，遠方的屋簷輪廓在陽光下閃耀。我在心裡想，故宮不僅保存了文物，更保存了我們與歷史之間那份溫柔的連結。','travel',22,NULL,1,12,'2025-11-11 11:01:57','2025-11-11 19:08:40');
/*!40000 ALTER TABLE `posts` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `product_categories`
--

DROP TABLE IF EXISTS `product_categories`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_categories` (
  `category_id` int NOT NULL AUTO_INCREMENT,
  `category_name` varchar(100) NOT NULL,
  `parent_name` varchar(100) DEFAULT NULL,
  `description` text,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
